public class ShaderExample {
    public static void main(String[] args) {
        // Create a new shader program object
        Shader shader = new Shader();

        // Load the vertex and fragment shaders from file
        String vertexShaderSource = "vert.glsl";
        String fragmentShaderSource = "frag.glsl";
        shader.loadShader(vertexShaderSource, fragmentShaderSource);

        // Bind the program to use for rendering
        shader.bind();

        // Set a float uniform variable with value 1.0
        float value = 1.0f;
        shader.uniformf("float_uniform", value);

        // Set a vector uniform variable with values 2.0, 3.0 and 4.0
        float[] vecValues = {2.0f, 3.0f, 4.0f};
        shader.uniformf("vec_uniform", vecValues);

        // Set a matrix uniform variable with values from a Matrix4f object
        Matrix4f mat = new Matrix4f();
        mat.setIdentity();
        shader.unifromMat4("mat_uniform", mat);
    }
}

